/**
 * ConversationSocket — manages the WebSocket connection to the server and
 * captures microphone audio as raw PCM for forwarding.
 *
 * Audio pipeline:
 *   getUserMedia (mono, 16 kHz)
 *   → AudioContext (sampleRate: 16 000)
 *   → ScriptProcessorNode (bufferSize: 4 096 = ~256 ms)
 *   → Float32 → Int16 PCM conversion
 *   → binary WebSocket frame → server → ElevenLabs Scribe
 *
 * Server → browser message types:
 *   transcript        — live partial or committed text per speaker
 *   turn_complete     — a speaker turn was finalised
 *   argument_update   — streaming token from Claude
 *   argument_complete — Claude finished for this turn
 *   error             — server-side error string
 *   session_ended     — graceful session close
 */

// ── Shared types (re-exported for use in React components) ─────────────────

export type SpeakerLabel = "speaker_a" | "speaker_b" | "unknown";
export type ArgumentRole = "argument" | "counterargument";
export type WordStatus = "partial" | "final";

export interface TranscriptEntry {
  turnId: string;
  speaker: SpeakerLabel;
  /** Accumulated text for this turn (partial text is replaced by final). */
  text: string;
  isPartial: boolean;
}

export interface ArgumentUpdate {
  turnId: string;
  speaker: SpeakerLabel;
  role: ArgumentRole;
  delta: string;
  isFinal: boolean;
}

// ── Internal server message shapes ────────────────────────────────────────────

interface ServerTranscriptMsg {
  type: "transcript";
  speaker: SpeakerLabel;
  text: string;
  is_partial: boolean;
  turn_id: string;
}

interface ServerTurnCompleteMsg {
  type: "turn_complete";
  speaker: SpeakerLabel;
  turn_id: string;
}

interface ServerArgumentUpdateMsg {
  type: "argument_update";
  speaker: SpeakerLabel;
  role: ArgumentRole;
  delta: string;
  turn_id: string;
  is_final: boolean;
}

interface ServerArgumentCompleteMsg {
  type: "argument_complete";
  speaker: SpeakerLabel;
  turn_id: string;
}

interface ServerErrorMsg {
  type: "error";
  message: string;
}

interface ServerSessionEndedMsg {
  type: "session_ended";
}

type ServerMessage =
  | ServerTranscriptMsg
  | ServerTurnCompleteMsg
  | ServerArgumentUpdateMsg
  | ServerArgumentCompleteMsg
  | ServerErrorMsg
  | ServerSessionEndedMsg;

// ── Callbacks ─────────────────────────────────────────────────────────────────

export interface ConversationCallbacks {
  onTranscript?: (entry: TranscriptEntry) => void;
  onArgumentUpdate?: (update: ArgumentUpdate) => void;
  onArgumentComplete?: (speaker: SpeakerLabel, turnId: string) => void;
  onTurnComplete?: (speaker: SpeakerLabel, turnId: string) => void;
  onError?: (message: string) => void;
  onSessionEnded?: () => void;
  onConnected?: () => void;
  onDisconnected?: () => void;
}

// ── PCM constants ─────────────────────────────────────────────────────────────

const TARGET_SAMPLE_RATE = 16_000;
const SCRIPT_PROCESSOR_BUFFER = 4_096; // ~256 ms at 16 kHz

// ── ConversationSocket ────────────────────────────────────────────────────────

export class ConversationSocket {
  private ws: WebSocket | null = null;
  private audioCtx: AudioContext | null = null;
  private sourceNode: MediaStreamAudioSourceNode | null = null;
  private processorNode: ScriptProcessorNode | null = null;
  private stream: MediaStream | null = null;

  private readonly wsUrl: string;
  private readonly callbacks: ConversationCallbacks;

  constructor(wsUrl: string, callbacks: ConversationCallbacks = {}) {
    this.wsUrl = wsUrl;
    this.callbacks = callbacks;
  }

  // ── Lifecycle ──────────────────────────────────────────────────────────────

  /** Connect WebSocket, then request mic access and start streaming. */
  async connect(): Promise<void> {
    await this._openWebSocket();
    await this._startMic();
  }

  /** Send end_session control message and release all resources. */
  async disconnect(): Promise<void> {
    this._stopMic();
    if (this.ws && this.ws.readyState === WebSocket.OPEN) {
      this.ws.send(JSON.stringify({ type: "end_session" }));
      // Give the server a moment to acknowledge before hard-closing.
      await new Promise<void>((resolve) => setTimeout(resolve, 300));
      this.ws.close(1000, "user-disconnect");
    }
    this.ws = null;
  }

  // ── Private: WebSocket ─────────────────────────────────────────────────────

  private async _openWebSocket(): Promise<void> {
    return new Promise((resolve, reject) => {
      const ws = new WebSocket(this.wsUrl);
      ws.binaryType = "arraybuffer";

      const timeout = setTimeout(() => {
        ws.close();
        reject(new Error("WebSocket connection timed out"));
      }, 10_000);

      ws.onopen = () => {
        clearTimeout(timeout);
        this.ws = ws;
        this.callbacks.onConnected?.();
        resolve();
      };

      ws.onerror = (ev) => {
        clearTimeout(timeout);
        reject(new Error("WebSocket error during connect"));
      };

      ws.onclose = () => {
        this.callbacks.onDisconnected?.();
      };

      ws.onmessage = (ev) => this._handleServerMessage(ev.data as string);
    });
  }

  private _handleServerMessage(raw: string): void {
    let msg: ServerMessage;
    try {
      msg = JSON.parse(raw) as ServerMessage;
    } catch {
      console.warn("[ConversationSocket] Non-JSON message:", raw);
      return;
    }

    switch (msg.type) {
      case "transcript":
        this.callbacks.onTranscript?.({
          turnId: msg.turn_id,
          speaker: msg.speaker,
          text: msg.text,
          isPartial: msg.is_partial,
        });
        break;

      case "turn_complete":
        this.callbacks.onTurnComplete?.(msg.speaker, msg.turn_id);
        break;

      case "argument_update":
        this.callbacks.onArgumentUpdate?.({
          turnId: msg.turn_id,
          speaker: msg.speaker,
          role: msg.role,
          delta: msg.delta,
          isFinal: msg.is_final,
        });
        break;

      case "argument_complete":
        this.callbacks.onArgumentComplete?.(msg.speaker, msg.turn_id);
        break;

      case "error":
        console.error("[ConversationSocket] Server error:", msg.message);
        this.callbacks.onError?.(msg.message);
        break;

      case "session_ended":
        this._stopMic();
        this.callbacks.onSessionEnded?.();
        break;
    }
  }

  // ── Private: mic capture ───────────────────────────────────────────────────

  private async _startMic(): Promise<void> {
    let micStream: MediaStream;
    try {
      micStream = await navigator.mediaDevices.getUserMedia({
        audio: {
          channelCount: 1,
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
          // Request 16 kHz; the browser will resample if needed.
          sampleRate: TARGET_SAMPLE_RATE,
        },
      });
    } catch (err) {
      const message =
        err instanceof DOMException && err.name === "NotAllowedError"
          ? "Microphone permission denied. Please allow mic access and try again."
          : `Could not access microphone: ${(err as Error).message}`;
      this.callbacks.onError?.(message);
      throw new Error(message);
    }

    this.stream = micStream;

    // Create an AudioContext that processes audio at exactly 16 kHz.
    this.audioCtx = new AudioContext({ sampleRate: TARGET_SAMPLE_RATE });
    this.sourceNode = this.audioCtx.createMediaStreamSource(micStream);

    // ScriptProcessorNode is deprecated but universally supported.
    // Buffer size 4096 at 16 kHz ≈ 256 ms per callback.
    this.processorNode = this.audioCtx.createScriptProcessor(
      SCRIPT_PROCESSOR_BUFFER,
      1, // input channels
      1  // output channels
    );

    this.processorNode.onaudioprocess = (ev: AudioProcessingEvent) => {
      if (!this.ws || this.ws.readyState !== WebSocket.OPEN) return;

      const float32 = ev.inputBuffer.getChannelData(0);
      const int16 = _float32ToInt16(float32);
      this.ws.send(int16.buffer);
    };

    // source → processor → destination keeps the graph alive.
    this.sourceNode.connect(this.processorNode);
    this.processorNode.connect(this.audioCtx.destination);
  }

  private _stopMic(): void {
    if (this.processorNode) {
      this.processorNode.disconnect();
      this.processorNode.onaudioprocess = null;
      this.processorNode = null;
    }
    if (this.sourceNode) {
      this.sourceNode.disconnect();
      this.sourceNode = null;
    }
    if (this.audioCtx) {
      this.audioCtx.close().catch(() => {});
      this.audioCtx = null;
    }
    if (this.stream) {
      this.stream.getTracks().forEach((t) => t.stop());
      this.stream = null;
    }
  }
}

// ── Utility ───────────────────────────────────────────────────────────────────

/** Convert Float32 PCM samples in [-1, 1] to Int16 little-endian PCM. */
function _float32ToInt16(float32: Float32Array): Int16Array {
  const out = new Int16Array(float32.length);
  for (let i = 0; i < float32.length; i++) {
    const clamped = Math.max(-1, Math.min(1, float32[i]));
    out[i] = clamped < 0 ? clamped * 32_768 : clamped * 32_767;
  }
  return out;
}
